"use strict";const tabcontent=document.getElementsByClassName("profile-tab-content"),tablinks=document.getElementsByClassName("profile-tab-link"),windowHash=window.location.hash.replace("#","");function changeTab(evt,tabName){for(var i=0;i<tabcontent.length;i++)tabcontent[i].style.display="none";for(i=0;i<tablinks.length;i++)tablinks[i].className=tablinks[i].className.replace(" active","");document.getElementById(tabName).style.display="block",evt.currentTarget.className+=" active"}""!=window.location.hash&&["bio","settings","posts"].includes(windowHash)?document.getElementById(window.location.hash.replace("#","")).click():(console.log("clicking default"),document.getElementById("bio").click());